Map<String, String> parsePaxHeaders(final InputStream i) throws IOException {
    final Map<String, String> headers = new HashMap<String, String>(globalPaxHeaders);
    // Format is 'length keyword=value\n';
    while(true){
      int ch;
      int len = 0;
      int read = 0;
      while((ch = i.read()) != -1) {
        read++;
        if (ch == ' '){
          // Get keyword
          final ByteArrayOutputStream coll = new ByteArrayOutputStream();
          while((ch = i.read()) != -1) {
            read++;
            if (ch == '='){
              // end of keyword
              final String keyword = coll.toString(CharsetNames.UTF_8);
              if (keyword == null) {
                continue;
              }
              // Get rest of entry
              final int restLen = len - read;
              if (restLen <= 0) {
                return headers;
              }
              final byte[] rest = new byte[restLen];
              final int got = IOUtils.readFully(i, rest);
              if (got != restLen) {
                throw new IOException("Failed to read Paxheader. Expected " + restLen + " bytes, read " + got);
              }
              // Drop trailing NL
              final String value = new String(rest, 0, restLen - 1, CharsetNames.UTF_8);
              headers.put(keyword, value);
              break;
            }
            coll.write((byte) ch);
          }
          break; // Processed single header
        }
        len *= 10;
        len += ch - '0';
      }
      if (ch == -1) {
        // EOF
        break;
      }
    }
    return headers;
  }

